={{ 
  (() => {
    const loc = ($json?.query?.storage_location || "").trim();
    const base = "AND({origin_strain_regulated}, {item_category} = 'freezedriedmushrooms', NOT(OR({storage_location} = 'Shipped', {storage_location} = 'Consumed', {storage_location} = 'Expired')))";
    if (!loc) return "=" + base;
    return "=AND(" + base + ", {storage_location} = '" + loc.replace(/'/g, "\\'") + "')";
  })()
}}

parameters.jsCode:
const products =  $('Airtable - List Products').all().map(i => i.json);
const locations = $('Airtable - List Locations').all().map(i => i.json);

function asArray(v) {
  if (v == null) return [];
  return Array.isArray(v) ? v : [v];
}

function stripIndexPrefix(x) {
  if (x == null) return null;
  const s = String(x);
  const m = s.match(/^\d+:(rec[a-zA-Z0-9]+)/);
  return m ? m[1] : s;
}

const locById = new Map();
for (const rec of locations) {
  const f = rec.fields ?? rec;
  const name = (f.name ?? '').toString().trim();
  if (rec.id) locById.set(rec.id, name);
}

const EXCLUDE_LOCATIONS = new Set(['Shipped','Consumed','Expired']);

const out = [];
for (const rec of products) {
  const f = rec.fields ?? rec;
  const product_id = f.product_id;
  if (!product_id) continue;

  const locIds = asArray(f.storage_location)
    .map(stripIndexPrefix)
    .filter(x => x && x !== "undefined");

  const locNames = locIds.map(id => locById.get(id)).filter(Boolean);

  if (locNames.some(n => EXCLUDE_LOCATIONS.has(n))) continue;

  out.push({
    airtable_record_id: rec.id,
    mushroomprocess_product_id: product_id,
    item_name: (asArray(f.name)[0] ?? null),
    strain: (asArray(f.species_strain)[0] ?? null),
    net_weight_g: f.net_weight_g ?? null,
    unit: "g",
    storage_location: locNames[0] ?? null,
  });
}

let filtered = out;
const req = $('Webhook - List Products').first().json;

const requestedLoc = (req?.query?.storage_location || "").trim();
if (requestedLoc) {
  filtered = out.filter(p => (p.storage_location || "").trim() === requestedLoc);
}

return [{ json: { ok: true, data: filtered } }];
